}

function requireNonEmptyStringArray(issues: string[], field: string, value: string[]) {
	if (value.length === 0) {
		issues.push(`${field} must include at least one value`);
		return;
	}

	for (const item of value) {
		requireNonEmptyString(issues, field, item);
