+							nodes {
+								__typename
+								... on ProjectV2ItemFieldTextValue {
+									text
+									field {
+										name
+									}
+								}
+								... on ProjectV2ItemFieldSingleSelectValue {
+									name
+									field {
+										name
+									}
+								}
+							}
+						}
+					}
+					pageInfo {
+						hasNextPage
+						endCursor
+					}
+				}
+			}
+		}
+	}
