import { loadRhapsodyGitHubEnv, type RhapsodyGitHubEnv } from "@/lib/config";

export type GitHubProjectIssueWorkItem = {
	issueNumber: number;
	issueTitle: string;
	issueUrl: string;
	issueState: string;
	issueBody: string | null;
	projectStatus: string | null;
	repository: {
		owner: string;
		name: string;
	};
};

