	owner: string;
	repository: string;
	projectNumber: number;
	statusField: string;
};

type GitHubProjectItemsPage = {
	items: GitHubProjectIssueWorkItem[];
	hasNextPage: boolean;
	endCursor: string | null;
};

type GitHubProjectItemsGraphQLResponse = {
	data?: {
		user?: {
			projectV2?: {
				items?: {
					nodes?: GitHubProjectItemNode[] | null;
					pageInfo?: {
						hasNextPage?: boolean;
						endCursor?: string | null;
