export async function GET(request: Request) {
	const auth = requireAdminAuth(request);

	if (!auth.ok) {
		return auth.response;
	}

	const url = new URL(request.url);
	const runId = url.searchParams.get("runId");

	if (!runId) {
		return Response.json({ error: "Missing runId." }, { status: 400 });
	}

	const run = getRun(runId);
	const runHandle = run as
		| {
				exists?: () => Promise<boolean>;
				status?: () => Promise<string>;
				returnValue?: () => Promise<unknown>;
		  }
		| undefined;

	if (runHandle?.exists && !(await runHandle.exists())) {
		return Response.json({ error: "Workflow run not found." }, { status: 404 });
	}

	const status = runHandle?.status ? await runHandle.status() : "unknown";
	const response: { runId: string; status: string; returnValue?: unknown } = {
		runId,
		status,
	};

	if (status !== "running") {
		if (runHandle?.returnValue) {
			response.returnValue = await runHandle.returnValue();
		}
	}

	return Response.json(response);
}

