	callback_status: response.status,
	callback_ok: response.ok,
	callback_body: safeJson(text),
}));

if (!response.ok) {
	process.exitCode = 1;
}

function safeJson(text) {
	if (!text) {
		return null;
	}

	try {
		return JSON.parse(text);
	} catch {
		return text;
	}
}
`;
}

