function loadRequiredEnv<const TKey extends string>(
	env: NodeJS.ProcessEnv,
	keys: readonly TKey[],
): Record<TKey, string> {
	const issues: string[] = [];
	const values = {} as Record<TKey, string>;

	for (const key of keys) {
		const value = env[key];

		if (!value?.trim()) {
			issues.push(`${key} is required`);
			continue;
		}

		values[key] = value;
	}

	if (issues.length > 0) {
		throw new RhapsodyConfigError(issues);
	}

	return values;
}

function loadOptionalEnv<const TKey extends string>(
	env: NodeJS.ProcessEnv,
	keys: readonly TKey[],
): Partial<Record<TKey, string>> {
	const values = {} as Partial<Record<TKey, string>>;

	for (const key of keys) {
		const value = env[key];

		if (value?.trim()) {
			values[key] = value;
		}
	}

	return values;
}

